import{_ as t,o as d,c as o,a2 as a}from"./chunks/framework.QoSTM79V.js";const u=JSON.parse('{"title":"文档资产归档边界","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/06-document-assets.md","filePath":"mango-pmo/rules/06-document-assets.md"}'),l={name:"mango-pmo/rules/06-document-assets.md"};function i(c,e,r,n,s,m){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="文档资产归档边界" tabindex="-1">文档资产归档边界 <a class="header-anchor" href="#文档资产归档边界" aria-label="Permalink to &quot;文档资产归档边界&quot;">​</a></h1><h2 id="_1-定位" tabindex="-1">1. 定位 <a class="header-anchor" href="#_1-定位" aria-label="Permalink to &quot;1. 定位&quot;">​</a></h2><ul><li>本文件约束 Mango 规范、使用说明、设计文档、Sprint 计划和交付记录的归档边界。</li><li><code>mango-pmo</code> 是唯一长期规范源。</li><li><code>mango-docs</code> 不是规范源，只保存设计、计划、交付和历史材料。</li></ul><h2 id="_2-判定规则" tabindex="-1">2. 判定规则 <a class="header-anchor" href="#_2-判定规则" aria-label="Permalink to &quot;2. 判定规则&quot;">​</a></h2><p>一段内容按最强约束归档：</p><table tabindex="0"><thead><tr><th>内容类型</th><th>判定标准</th><th>归档位置</th></tr></thead><tbody><tr><td>规范</td><td>长期有效，包含必须、禁止、流程门禁、架构边界、质量门禁、命名、权限、租户、事务、发布或测试约束</td><td><code>mango-pmo/rules/**</code></td></tr><tr><td>角色约束</td><td>定义 Agent 角色职责、必做事项、禁止事项和输出要求</td><td><code>mango-pmo/agents/**</code></td></tr><tr><td>使用说明</td><td>面向开发者操作某个模块或工具，包含命令、配置示例、常见错误、使用步骤</td><td>模块 README、开发者指南或工具 README</td></tr><tr><td>设计文档</td><td>解释一次能力的背景、方案、模块边界、接口、数据和取舍</td><td><code>mango-docs/designs/**</code></td></tr><tr><td>Sprint 计划</td><td>描述一次迭代的目标、范围、改动项、验证方式、完成标准和遗留问题</td><td><code>mango-docs/plans/**</code></td></tr><tr><td>交付记录</td><td>记录一次任务或迭代的验证结果、证据、例外和风险</td><td><code>mango-docs/evidence/**</code> 或 <code>mango-docs/plans/**</code></td></tr><tr><td>E2E 脚本</td><td>可重复执行的端到端测试、回归脚本、fixture 和支持代码</td><td>对应应用、包或模块的正式测试目录</td></tr><tr><td>测试结果基线</td><td>某次正式验收的命令、环境、数据集、账号/租户标识、结果摘要、报告和证据路径</td><td><code>mango-docs/evidence/**</code> 或 <code>mango-docs/plans/**</code></td></tr></tbody></table><p>如果同一段内容同时满足多个类型，按优先级归档：规范 &gt; 角色约束 &gt; 使用说明 &gt; 设计文档 &gt; Sprint 计划 &gt; 交付记录。</p><h2 id="_3-规范" tabindex="-1">3. 规范 <a class="header-anchor" href="#_3-规范" aria-label="Permalink to &quot;3. 规范&quot;">​</a></h2><ul><li>长期规则只允许写在 <code>mango-pmo/rules/**</code>。</li><li>规则文件必须短、硬、可执行。</li><li>规则只能维护一份；其它文档只能链接规则源，不得复制规则正文。</li><li>新增规则必须接入 <code>mango-pmo/rules/index.json</code>，保证 preflight 可加载。</li><li>修改规则时必须说明影响范围和验证命令。</li></ul><h2 id="_4-使用说明" tabindex="-1">4. 使用说明 <a class="header-anchor" href="#_4-使用说明" aria-label="Permalink to &quot;4. 使用说明&quot;">​</a></h2><ul><li>模块使用说明放在对应模块 README 或开发者指南。</li><li>工具使用说明放在对应工具 README。</li><li>使用说明可以包含示例命令、YAML 配置、注解用法、错误排查和操作步骤。</li><li>使用说明引用长期约束时，只能链接 <code>mango-pmo</code> 规则源。</li><li>禁止在使用说明中新增必须遵守的长期规则。</li></ul><h2 id="_5-设计与计划" tabindex="-1">5. 设计与计划 <a class="header-anchor" href="#_5-设计与计划" aria-label="Permalink to &quot;5. 设计与计划&quot;">​</a></h2><ul><li>设计文档只记录本次能力的背景、方案、边界、接口、数据、测试范围和风险。</li><li>Sprint 计划只记录本次迭代的目标、范围、改动项、验证方式、完成标准和遗留问题。</li><li>设计文档和 Sprint 计划可以提出待治理问题，但不能把待治理建议写成长期规则。</li><li>设计或计划中出现长期规则时，必须迁移到 <code>mango-pmo/rules/**</code>，原文改为链接规则源。</li></ul><h2 id="_6-交付记录" tabindex="-1">6. 交付记录 <a class="header-anchor" href="#_6-交付记录" aria-label="Permalink to &quot;6. 交付记录&quot;">​</a></h2><ul><li>交付记录只记录某次任务的事实、验证结果、截图、日志摘要、证据路径、例外和风险。</li><li><code>mango-docs/evidence/**</code> 只保存最终证据，不保存生成项目、依赖缓存、构建产物或运行日志。</li><li>可复用脚本不能长期放在 evidence 目录；必须沉淀到正式测试目录或工具目录。</li><li>E2E 测试结果基线属于交付记录，必须能追溯到对应 E2E 脚本、测试命令、环境、数据集和报告路径。</li><li>evidence 中允许保存当次执行脚本副本或报告摘要；长期维护入口必须放在正式测试目录。</li></ul><h2 id="_7-多数据源说明落位" tabindex="-1">7. 多数据源说明落位 <a class="header-anchor" href="#_7-多数据源说明落位" aria-label="Permalink to &quot;7. 多数据源说明落位&quot;">​</a></h2><ul><li>模块默认数据源声明规则、覆盖优先级、禁止绕过租户/权限/事务边界等长期约束归档到 <code>mango-pmo/rules/backend/07-persistence.md</code> 或相关 PMO 规则。</li><li><code>@PersistenceDataSource</code>、<code>PersistenceDataSourceContext</code>、YAML 配置示例、常见错误排查归档到 <code>mango-infra-persistence-starter</code> 使用说明或开发者指南。</li><li>多数据源设计背景、方案取舍和历史交付记录保留在 <code>mango-docs/designs/**</code>、<code>mango-docs/plans/**</code> 或 <code>mango-docs/evidence/**</code>。</li></ul><h2 id="_8-禁止事项" tabindex="-1">8. 禁止事项 <a class="header-anchor" href="#_8-禁止事项" aria-label="Permalink to &quot;8. 禁止事项&quot;">​</a></h2><ul><li>禁止在 <code>mango-docs</code> 新增规范文件。</li><li>禁止在 <code>mango-docs</code> 维护规则入口。</li><li>禁止在设计文档、Sprint 计划、交付记录或 README 中复制长期规则正文。</li><li>禁止同一规则在 <code>mango-pmo</code>、<code>mango-docs</code>、README 和 Agent 入口多处维护。</li></ul>',19)])])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
